import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';

class Twitter extends React.Component {
  render() {
    return (
      <svg
        xmlns="http://www.w3.org/2000/svg"
        viewBox="0 0 400 325"
        role="img"
        className="twitter-icon"
      >
        <path
          fill="#1da1f2"
          d="M125.792 325c150.944 0 233.504-125.048 233.504-233.49 0-3.55 0-7.087-.24-10.606A166.976 166.965 0 00400 38.426a163.808 163.798 0 01-47.136 12.911 82.352 82.347 0 0036.08-45.389 164.464 164.454 0 01-52.112 19.919 82.144 82.139 0 00-139.856 74.843A232.992 232.977 0 0127.84 14.972a82.128 82.123 0 0025.408 109.545A81.456 81.45 0 0116 114.245v1.04a82.096 82.09 0 0065.84 80.443 81.936 81.93 0 01-37.056 1.408 82.16 82.155 0 0076.672 56.989 164.672 164.662 0 01-101.92 35.197A167.056 167.045 0 010 288.138a232.336 232.321 0 00125.792 36.798"
        />
      </svg>
    );
  }
}

class QuotesLeft extends React.Component {
  render() {
    return (
      <svg
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
        className="quotes-left"
        viewBox="0 0 512 512"
        role="img"
      >
        <path
          fill="currentColor"
          d="M464 256h-80v-64c0-35.3 28.7-64 64-64h8c13.3 0 24-10.7 24-24V56c0-13.3-10.7-24-24-24h-8c-88.4 0-160 71.6-160 160v240c0 26.5 21.5 48 48 48h128c26.5 0 48-21.5 48-48V304c0-26.5-21.5-48-48-48zm-288 0H96v-64c0-35.3 28.7-64 64-64h8c13.3 0 24-10.7 24-24V56c0-13.3-10.7-24-24-24h-8C71.6 32 0 103.6 0 192v240c0 26.5 21.5 48 48 48h128c26.5 0 48-21.5 48-48V304c0-26.5-21.5-48-48-48z"
        />
      </svg>
    );
  }
}

class App extends React.Component {
  state = {
    quotesArr: null,
    quote: null,
    author: null,
  };
  componentDidMount = () => {
    fetch(
      'https://gist.githubusercontent.com/camperbot/5a022b72e96c4c9585c32bf6a75f62d9/raw/e3c6895ce42069f0ee7e991229064f167fe8ccdc/quotes.json'
    )
      .then(res => res.json())
      .then(resJSON => {
        const quotesArr = resJSON.quotes;
        const randomQuote =
          quotesArr[Math.floor(Math.random() * quotesArr.length)];
        this.setState({
          quotesArr,
          quote: randomQuote.quote,
          author: randomQuote.author,
        });
      });
  };

  updateQuote = () => {
    const quotesArr = this.state.quotesArr;
    const randomQuote = quotesArr[Math.floor(Math.random() * quotesArr.length)];
    this.setState({
      quotesArr,
      quote: randomQuote.quote,
      author: randomQuote.author,
    });
  };

  render = () => {
    return (
      <main className="App-main">
        <div id="quote-box">
          <div id="text" data-loading={this.state.quote === null}>
            {this.state.quote && (
              <>
                <QuotesLeft />
                <span>{this.state.quote}</span>
              </>
            )}
          </div>
          <div id="author" data-loading={this.state.author === null}>
            {'- ' + this.state.author}
          </div>
          <div
            id="new-quote"
            onClick={this.updateQuote}
            data-loading-disable={this.state.quote === null}
          >
            New quote
          </div>
          <a
            id="tweet-quote"
            href={
              this.state.quote &&
              'https://twitter.com/intent/tweet?text=' +
                encodeURIComponent(`${this.state.quote}\n${this.state.author}`)
            }
            target="_blank"
            rel="noopener noreferrer"
            data-loading={this.state.quote === null}
          >
            {this.state.quote !== null && (
              <>
                <Twitter />
                <span>Tweet this quote</span>
              </>
            )}
          </a>
        </div>
      </main>
    );
  };
}

ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
);
